test('mocks a fruit and doesn\'t call api', async ({ page }) => {
  // Intercept the API call
  await page.route('*/**/api/v1/fruits', async route => {
    const json = [{ name: 'Strawberry', id: 21 }];
    await route.fulfill({ json });
  });

  // Go to the page - the frontend will receive the mock data
  await page.goto('https://demo.playwright.dev/api-mocking');

  // Assert that the mocked fruit is visible
  await expect(page.getByText('Strawberry')).toBeVisible();
});

import { test as base } from '@playwright/test';

// Extend base test to include a custom 'todoPage' fixture
export const test = base.extend({
  todoPage: async ({ page }, use) => {
    const todoPage = new TodoPage(page);
    await todoPage.goto();
    await todoPage.addToDo('item1');

    // Pass the fixture to the test
    await use(todoPage);

    // Teardown (if necessary) runs after the test
    await todoPage.removeAll();
  },
});
